 {"id":"asupersync-1qfd0.26","title":"[audit][ambient] Remove stale test-only HTTP/1 spawn finding and harden ambient catalog matching","description":"The ambient-authority catalog in src/audit/ambient.rs still lists a critical std::thread::spawn finding in src/http/h1/stream.rs, but the only remaining spawn site is under #[cfg(test)] and should not count as production ambient authority. Remove the stale catalog entry and strengthen the matching test so known findings must resolve against non-test, non-comment code, preventing future false positives.","status":"closed","priority":1,"issue_type":"bug","assignee":"FuchsiaHollow","estimated_minutes":45,"created_at":"2026-03-09T01:08:22.563569888Z","created_by":"ubuntu","updated_at":"2026-03-09T01:55:22.415847418Z","closed_at":"2026-03-09T01:55:22.415822001Z","close_reason":"Completed","source_repo":".","compaction_level":0,"original_size":0,"labels":["ambient","audit","testing"],"dependencies":[{"issue_id":"asupersync-1qfd0.26","depends_on_id":"asupersync-1qfd0","type":"parent-child","created_at":"2026-03-09T01:08:22.563569888Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"asupersync-1qfd0.27","title":"[audit][web] Map RequestRegion cancellation to 499 Client Closed Request","description":"Fresh-eyes audit slice under asupersync-1qfd0: RequestRegion currently converts cancelled request handling into HTTP 503 Service Unavailable even though the runtime Outcome docs recommend 499 Client Closed Request for cancelled request work. Add the missing web status constant, switch the RequestRegion cancellation response mapping, and add regression coverage so request-cancel semantics stay aligned with the documented lattice.","status":"closed","priority":1,"issue_type":"bug","assignee":"CoralCompass","estimated_minutes":45,"created_at":"2026-03-09T01:09:55.256134548Z","created_by":"WindyCave","updated_at":"2026-03-10T18:56:00.615539271Z","closed_at":"2026-03-10T18:56:00.615520856Z","close_reason":"Already satisfied in the current tree; validated by source audit and remote lib check","source_repo":".","compaction_level":0,"original_size":0,"labels":["audit","cancellation","http","web"],"dependencies":[{"issue_id":"asupersync-1qfd0.27","depends_on_id":"asupersync-1qfd0","type":"parent-child","created_at":"2026-03-09T01:09:55.256134548Z","created_by":"WindyCave","metadata":"{}","thread_id":""}],"comments":[{"id":2474,"issue_id":"asupersync-1qfd0.27","author":"CoralCompass","text":"Audit result: current tree already satisfies this bead.

